SELECT year, incarceration_rate
FROM incarceration_data
ORDER BY year ASC;

SELECT facility_name, current_occupancy
FROM facility_data
ORDER BY current_occupancy DESC;

SELECT year, population
FROM incarceration_data
ORDER BY year;

SELECT facility_id, SUM(occupied_beds) AS total_occupied_beds
FROM bed_utilization
GROUP BY facility_id;

SELECT AVG(incarceration_rate) AS average_incarceration_rate
FROM incarceration_data
WHERE year = 2023;

SELECT SUM(occupied_beds) AS total_occupied_beds
FROM bed_utilization
WHERE facility_id = 1 AND year = 2023;

SELECT MAX(incarceration_rate) AS max_incarceration_rate
FROM incarceration_data
WHERE state_id = 1;

SELECT incarceration_rate
FROM incarceration_data
WHERE year = 2023;

SELECT MAX(utilization_rate) AS max_utilization_rate
FROM bed_utilization
WHERE year = 2023;

SELECT capacity AS total_beds
FROM facility_data
WHERE facility_id = 1;

SELECT year, AVG(incarceration_rate) AS avg_incarceration_rate
FROM incarceration_data
WHERE year = 2020;
